import { describe, expect, it, vi } from "vitest";
import { parseUpdateMode } from "./update.js";
describe("parseUpdateMode", () => {
    it('defaults to "all" for undefined', () => {
        expect(parseUpdateMode(undefined)).toBe("all");
    });
    it('accepts "all"', () => {
        expect(parseUpdateMode("all")).toBe("all");
    });
    it('accepts "plugin"', () => {
        expect(parseUpdateMode("plugin")).toBe("plugin");
    });
    it('accepts "sdk"', () => {
        expect(parseUpdateMode("sdk")).toBe("sdk");
    });
    it("throws on unknown modes", () => {
        expect(() => parseUpdateMode("everything")).toThrow(/Unknown update mode/);
    });
    // Help is honored anywhere in argv, not just when the mode slot is the flag,
    // so `update plugin -h` shows help instead of running an update.
    it.each([
        [["node", "update.js", "-h"]],
        [["node", "update.js", "--help"]],
        [["node", "update.js", "plugin", "-h"]],
        [["node", "update.js", "sdk", "--help"]],
    ])("prints help and exits 0 for argv %s", (argv) => {
        const origArgv = process.argv;
        process.argv = argv;
        // Throw from the mock so execution stops at the exit call, like a real exit.
        const mockExit = vi.spyOn(process, "exit").mockImplementation(() => {
            throw new Error("process.exit");
        });
        const mockLog = vi.spyOn(console, "log").mockImplementation(() => { });
        expect(() => parseUpdateMode(argv[2])).toThrow("process.exit");
        expect(mockExit).toHaveBeenCalledWith(0);
        expect(mockLog).toHaveBeenCalledWith(expect.stringContaining("Usage: update [mode]"));
        process.argv = origArgv;
        mockExit.mockRestore();
        mockLog.mockRestore();
    });
});
